<template><div class="timeline"><button v-for="(task,index) in tasks" :key="task.name" :class="{active:selected===task.name,failed:task.status==='Failed'}" @click="$emit('select',task)"><span class="node"><i>{{task.status==='Succeeded'?'✓':task.status==='Failed'?'×':index+1}}</i></span><div><b>{{task.task_name||task.name}}</b><StatusBadge :status="task.status"/></div><em v-if="index<tasks.length-1"/></button></div></template>
<script setup lang="ts">import StatusBadge from'../common/StatusBadge.vue';defineProps<{tasks:any[];selected?:string}>();defineEmits<{select:[any]}>()
</script>
<style scoped>.timeline{display:flex;align-items:flex-start;padding:21px 22px;overflow:auto}.timeline button{min-width:150px;position:relative;display:flex;align-items:center;gap:9px;border:0;background:none;color:var(--text-2);text-align:left;padding:0}.node{width:27px;height:27px;display:grid;place-items:center;border-radius:50%;background:rgba(71,201,143,.12);border:1px solid rgba(71,201,143,.35);z-index:1}.node i{font-style:normal;color:var(--success);font-size:13px}.timeline button.failed .node{background:rgba(231,99,111,.12);border-color:rgba(231,99,111,.4)}.timeline button.failed .node i{color:var(--danger)}.timeline button.active .node{box-shadow:0 0 0 3px rgba(119,103,232,.15);border-color:var(--primary)}.timeline b{display:block;font-size:13px;margin-bottom:5px}.timeline em{position:absolute;left:27px;top:13px;width:35px;height:1px;background:#303644}</style>

